import{bV as s,aZ as t,aL as E,u as n,v as o,H as l,I as i,bJ as r,G as c}from"./chunks/framework.BfzMay2U.js";const m=JSON.parse('{"title":"redis并发竞争问题以及分布式锁","description":"","frontmatter":{"title":"redis并发竞争问题以及分布式锁","date":"2023-01-15T21:24:10.000Z","categories":["Redis"],"tags":["cocurrence"]},"headers":[],"relativePath":"views/redis/redis-cocurrence-get-key.md","filePath":"views/redis/redis-cocurrence-get-key.md"}'),A={name:"views/redis/redis-cocurrence-get-key.md"};function B(p,e,u,k,D,b){const d=t("MermaidChart"),a=t("ClientOnly");return E(),n("div",null,[e[0]||(e[0]=o("h1",{id:"redis-并发竞争问题以及分布式锁",tabindex:"-1"},[l("redis 并发竞争问题以及分布式锁 "),o("a",{class:"header-anchor",href:"#redis-并发竞争问题以及分布式锁","aria-label":'Permalink to "redis 并发竞争问题以及分布式锁"'},"​")],-1)),e[1]||(e[1]=o("h2",{id:"并发竞争",tabindex:"-1"},[l("并发竞争 "),o("a",{class:"header-anchor",href:"#并发竞争","aria-label":'Permalink to "并发竞争"'},"​")],-1)),e[2]||(e[2]=o("ul",null,[o("li",null,[l("多个客户端同时并发写一个"),o("code",null,"key"),l("，本来应该先到的操作因为某些原因后到了，导致数据出错。")])],-1)),i(a,null,{default:r(()=>[i(d,{code:"graph%20TD%3B%0A%09A(%E7%B3%BB%E7%BB%9FA)%0A%09B(%E7%B3%BB%E7%BB%9FB)%0A%09C(%E7%B3%BB%E7%BB%9FC)%0A%09D(redis%20key%20%3D%20v1)%0A%09A%20--%20key%3Da%20--%3E%20D%0A%09B%20--%20key%3Db%20--%3E%20D%0A%09C%20--%20key%3Dc%20--%3E%20D%0A",showToolbar:"1"})]),_:1}),e[3]||(e[3]=o("p",null,[l("期望结果："),o("code",null,"v1->a->b->c")],-1)),e[4]||(e[4]=o("p",null,[l("可能因为某种原因"),o("code",null,"b"),l("延迟了，就会导致: "),o("code",null,"v1->a->c->b")],-1)),e[5]||(e[5]=o("h2",{id:"解决",tabindex:"-1"},[l("解决 "),o("a",{class:"header-anchor",href:"#解决","aria-label":'Permalink to "解决"'},"​")],-1)),i(a,null,{default:r(()=>[i(d,{code:"graph%20TD%3B%0A%09A(%E7%B3%BB%E7%BB%9FA)%0A%09B(%E7%B3%BB%E7%BB%9FB)%0A%09C(%E7%B3%BB%E7%BB%9FC)%0A%09D(redis%20key%20%3D%20v1)%0A%09E(zookeeper)%0A%09A%20--%3E%20E%20--%20key%3Da%20--%3E%20D%0A%09B%20--%3E%20E%20--%20key%3Db%20--%3E%20D%0A%09C%20--%3E%20E%20--%20key%3Dc%20--%3E%20D%0A",showToolbar:"1"})]),_:1}),e[6]||(e[6]=c('<p>使用分布式锁 ，比如常用的<code>zookeeper</code>，<code>redis</code>也自带分布式锁，但是用的很少</p><p>使用分布式锁流程</p><ul><li>系统 A 先拿到锁，修改值为<code>a</code></li><li>系统 B 拿不到锁，阻塞等待不会修改</li><li>系统 C 也拿不到锁，阻塞等待不会修改</li><li>系统 A 释放锁以后，系统 B 拿到锁，修改数据为<code>b</code></li></ul><blockquote><p>但是这样也是有问题的，分布式锁只是保证同一时间内只有一个系统来拿到这个锁，修改值，不能保证顺序到达问题，有可能还是<code>系统B</code>延迟了，没拿到锁，导致最终结果和期望值还是不一样。</p></blockquote><h3 id="按照时间更新" tabindex="-1">按照时间更新 <a class="header-anchor" href="#按照时间更新" aria-label="Permalink to &quot;按照时间更新&quot;">​</a></h3><p>修改数据的时候，携带时间戳，更新时判断时间戳是否为最新时间，最新时间则更新。</p><p>假设系统 A 的时间为<code>00:00:01</code>，系统 B 的时间为<code>00:00:02</code>，系统 C 的时间为<code>00:00:03</code>，这样当系统 B 到达比 C 晚的时候，因为有时间戳判断，也不会进行更新。</p><h3 id="解决办法" tabindex="-1">解决办法 <a class="header-anchor" href="#解决办法" aria-label="Permalink to &quot;解决办法&quot;">​</a></h3><ul><li>利用分布式锁，确保同一时间只有一个系统在操作某一个<code>redis key</code>，其他系统不能操作</li><li>利用时间戳，当时间戳最新时修改<code>redis key</code>的值，当时间戳比较旧时，忽略操作。</li></ul><h2 id="zookeeper" tabindex="-1">ZooKeeper <a class="header-anchor" href="#zookeeper" aria-label="Permalink to &quot;ZooKeeper&quot;">​</a></h2><ul><li><code>ZooKeeper</code>主要服务于分布式系统，可以用它来做：统一配置管理、统一命名服务、分布式锁、集群管理</li><li>它的目标就是封装好复杂易出错的关键服务，将简单易用的接口和性能高效、功能稳定的系统提供给用户</li><li>可以把它看成是树状的结构，它的节点是<code>znode</code><ul><li>持久节点：默认节点类型，创建节点的客户端与<code>zk</code>断开连接以后，节点依然存在</li><li>持久节点顺序节点：在创建节点时，<code>zk</code>会根据节点的创建时间，对节点进行编号</li><li>临时节点：创建节点的客户端与<code>zk</code>断开连接后，节点就会被删除</li><li>临时顺序节点：创建节点时，<code>zk</code>会根据节点的创建时间，对节点进行编号，创建节点的客户端与<code>zk</code>断开连接后，节点就会被删除；<code>zookeeper</code>就是选用这个实现的分布式锁</li></ul></li></ul>',11)),i(a,null,{default:r(()=>[i(d,{code:"graph%20TD%3B%0A%09A(%5B%E8%8E%B7%E5%8F%96%E9%94%81%5D)%0A%09B%7B%E6%98%AF%E5%90%A6%E5%8D%A0%E7%94%A8%7D%0A%09C(%E7%AD%89%E5%BE%85%E9%94%81)%0A%09D(%E5%88%9B%E5%BB%BA%E8%8A%82%E7%82%B9)%0A%09E%7B%E6%98%AF%E5%90%A6%E6%88%90%E5%8A%9F%7D%0A%09F(%E5%8D%A0%E7%94%A8%E9%94%81)%0A%09G(%E9%87%8A%E6%94%BE%E9%94%81)%0A%09A%20--%3E%20B%0A%09B%20--%20Y%20--%3E%20C%0A%09B%20--%20N%20--%3E%20D%0A%09D%20--%3E%20E%0A%09E%20--%20Y%20--%3E%20F%0A%09E%20--%20N%20--%3E%20C%0A%09F%20--%20%E5%AE%8C%E6%88%90%20--%3E%20G%0A%09F%20--%20%E4%B8%AD%E6%96%AD%20--%3E%20G%0A",showToolbar:"1"})]),_:1}),e[7]||(e[7]=c('<div class="tip custom-block"><p class="custom-block-title">提示</p><p>这个时候就知道为什么选用临时节点，因为当客户端没有释放锁，或者因为问题断开之后，就会删除节点，自动的释放锁。</p><p>为什么选用顺序节点：</p><blockquote><p>假如现在有一万个请求，但是只有一个能获取到锁，但是剩下 9999 个只能监听灯等待锁；当第一个完成之后，这 9999 个又会同时去获取锁，只能有一个拿到，剩下的继续等待，循环的这样执行下去，这种情况是有问题的。即：<code>羊群效应</code>和<code>惊群效应</code></p></blockquote><p>解决：</p><ul><li>创建临时顺序节点</li><li>判断是不是最小的节点</li><li>是最小的，获得锁 ，否则监听上一个的节点</li><li>释放锁后，后面的监听节点处理</li></ul><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/images/image-20230115163253398.png" alt="image-20230115163253398" loading="lazy"></p></div>',1))])}const _=s(A,[["render",B]]);export{m as __pageData,_ as default};
